 1	import type { FC } from 'react';
 2	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
 3	import { CredentialsDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/CredentialsDetailsItem';
 4	import { ExternalManagementLinkDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/ExternalManagementLinkDetailsItem';
 5	import { TypeDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/TypeDetailsItem';
 6	import { URLDetailsItem } from 'src/modules/Providers/views/details/components/DetailsSection/components/URLDetailsItem';
 7	import { getOpenstackProviderWebUILink } from 'src/modules/Providers/views/details/components/DetailsSection/utils/getOpenstackProviderWebUILink';
 8	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
 9	
10	import CreatedAtDetailsItem from '@components/DetailItems/CreatedAtDetailItem';
11	import NameDetailsItem from '@components/DetailItems/NameDetailItem';
12	import NamespaceDetailsItem from '@components/DetailItems/NamespaceDetailItem';
13	import OwnerDetailsItem from '@components/DetailItems/OwnerDetailItem';
14	import { DescriptionList } from '@patternfly/react-core';
15	
16	import type { DetailsSectionProps } from './utils/types';
17	
18	const OpenstackDetailsSection: FC<DetailsSectionProps> = ({ data }) => {
19	  const { t } = useForkliftTranslation();
20	  const { permissions, provider } = data;
21	
22	  if (!provider || !permissions) return null;
23	
24	  return (
25	    <ModalHOC>
26	      <DescriptionList
27	        columnModifier={{
28	          default: '2Col',
29	        }}
30	      >
31	        <TypeDetailsItem resource={provider} />
32	        <ExternalManagementLinkDetailsItem
33	          resource={provider}
34	          canPatch={permissions.canPatch}
35	          webUILinkText={t(`OpenStack dashboard UI`)}
36	          webUILink={getOpenstackProviderWebUILink(provider)}
37	        />
38	        <NameDetailsItem resource={provider} />
39	        <NamespaceDetailsItem resource={provider} />
40	        <URLDetailsItem
41	          resource={provider}
42	          canPatch={permissions.canPatch}
43	          helpContent={
44	            <ForkliftTrans>
45	              URL of the OpenStack Identity (Keystone) endpoint. For example:{' '}
46	              <strong>https://identity_service.com:5000/v3</strong>.
47	            </ForkliftTrans>
48	          }
49	        />
50	        <CredentialsDetailsItem resource={provider} />
51	        <CreatedAtDetailsItem resource={provider} />
52	        <OwnerDetailsItem resource={provider} />
53	      </DescriptionList>
54	    </ModalHOC>
55	  );
56	};
57	
58	export default OpenstackDetailsSection;

